INSERT INTO products (type, sku, gtin, mpn, name, slug, short_description, description, brand, item_condition, google_category, status, price, sale_price, min_price, max_price, manage_stock, min_order_qty, stock_qty, stock_status, weight, featured, meta_title, meta_description) VALUES ('simple', 'EB-72-THWM100', NULL, NULL, 'TOALLA HUMEDA WAIPEX (100uds) Multiuso x 100uds', 'toalla-humeda-waipex-100uds-multiuso-x-100uds', NULL, 'Descripción:Toallitas húmedas multiuso para limpieza diaria, diseñadas para limpiar superficies lisas y lavables de forma rápida y efectiva. Ideales para el uso cotidiano en el hogar, permiten mantener los espacios limpios sin esfuerzo ni complicaciones.Aptas para cocinas, baños, escritorios, mesas y muebles lavables. Una solución práctica para la limpieza diaria en distintos ambientes del hogar.Modo de uso:Abrir la tapa Flip Top, levantar la etiqueta, extraer una toallita y limpiar la superficie deseada. Cerrar correctamente el envase después de cada uso para conservar la humedad.Precauciones:Solo para uso externo. Evitar el contacto con los ojos. No arrojar al inodoro. Mantener fuera del alcance de los niños.Características y presentación:Dimensiones:15X20CM100PCS, con tapa', NULL, 'new', NULL, 'published', 1700, NULL, 1700, 1700, 0, 1, 0, 'in_stock', NULL, 0, NULL, NULL)
  ON DUPLICATE KEY UPDATE type=VALUES(type), gtin=VALUES(gtin), mpn=VALUES(mpn), name=VALUES(name), slug=VALUES(slug), short_description=VALUES(short_description), description=VALUES(description), brand=VALUES(brand), item_condition=VALUES(item_condition), google_category=VALUES(google_category), status=VALUES(status), price=VALUES(price), sale_price=VALUES(sale_price), min_price=VALUES(min_price), max_price=VALUES(max_price), manage_stock=VALUES(manage_stock), min_order_qty=VALUES(min_order_qty), stock_qty=VALUES(stock_qty), stock_status=VALUES(stock_status), weight=VALUES(weight), featured=VALUES(featured), meta_title=VALUES(meta_title), meta_description=VALUES(meta_description);
