INSERT INTO products (type, sku, gtin, mpn, name, slug, short_description, description, brand, item_condition, google_category, status, price, sale_price, min_price, max_price, manage_stock, min_order_qty, stock_qty, stock_status, weight, featured, meta_title, meta_description) VALUES ('simple', 'TG-TG-VPC12W', NULL, NULL, 'Vaso polipapel 12oz Blanco (20×50)', 'vaso-polipapel-12oz-blanco-20x50', 'Resistente y versátil, ideal para bebidas frías y calientes. Microondeable, calidad y rentabilidad en caja de 1000 unidades. Perfecto para cafeterías y delivery.', 'El Vaso Polipapel 12oz Blanco de Tugou es la solución ideal para negocios de cafeterías, delivery y servicios de alimentos. Fabricado en Polipapel-PE, este vaso combina durabilidad y funcionalidad, siendo resistente al congelado y microondeable, lo que lo hace perfecto para bebidas frías o calientes. Con una capacidad de 355 ml (12 oz), dimensiones de 112 mm de alto y 82 mm de diámetro, ofrece un diseño ergonómico y práctico para el uso diario. Su color blanco clásico aporta elegancia y versatilidad, adaptándose a cualquier ambiente. Ideal para cafeterías, restaurantes y servicios de delivery, este vaso es una opción sostenible y profesional. Empaquetado en cajas de 1.000 unidades (20 mangas por caja), es perfecto para negocios que buscan calidad, comodidad y rentabilidad en sus operaciones diarias. ¡Optimiza tu servicio con un producto diseñado para satisfacer las necesidades de tus clientes!', NULL, 'new', NULL, 'draft', 0, NULL, 0, 0, 0, 1, 0, 'in_stock', NULL, 0, NULL, NULL)
  ON DUPLICATE KEY UPDATE type=VALUES(type), gtin=VALUES(gtin), mpn=VALUES(mpn), name=VALUES(name), slug=VALUES(slug), short_description=VALUES(short_description), description=VALUES(description), brand=VALUES(brand), item_condition=VALUES(item_condition), google_category=VALUES(google_category), status=VALUES(status), price=VALUES(price), sale_price=VALUES(sale_price), min_price=VALUES(min_price), max_price=VALUES(max_price), manage_stock=VALUES(manage_stock), min_order_qty=VALUES(min_order_qty), stock_qty=VALUES(stock_qty), stock_status=VALUES(stock_status), weight=VALUES(weight), featured=VALUES(featured), meta_title=VALUES(meta_title), meta_description=VALUES(meta_description);
